#!/usr/bin/env python3
from pathlib import Path
import shutil
ROOT=Path.cwd(); cs=ROOT/'MainWindow.xaml.cs'
if not cs.exists(): raise SystemExit('ERRORE: MainWindow.xaml.cs non trovato')
b=cs.with_suffix(cs.suffix+'.prima_patch_output_multi.bak')
if not b.exists(): shutil.copy2(cs,b)
text=cs.read_text(encoding='utf-8-sig')
old='public sealed class ExerciseState { public string Code { get; set; } = DefaultCode; public TimeSpan Elapsed { get; set; } = TimeSpan.Zero; }'
new='public sealed class ExerciseState { public string Code { get; set; } = DefaultCode; public TimeSpan Elapsed { get; set; } = TimeSpan.Zero; public string CompileOutput { get; set; } = ""; public string ProgramOutput { get; set; } = ""; }'
if old in text: text=text.replace(old,new,1)
run_start=text.find('private async void Run_Click(object sender, RoutedEventArgs e)'); run_end=text.find('private async Task CompileAsync()',run_start)
if run_start<0 or run_end<0: raise SystemExit('ERRORE: Run_Click non trovato')
run_method=r'''private async void Run_Click(object sender, RoutedEventArgs e) { if (!_compilationAllowed) { MessageBox.Show("La compilazione è stata inibita dal docente.", "Compilazione non disponibile", MessageBoxButton.OK, MessageBoxImage.Information); return; } if (_verificationMode) { MessageBox.Show("Durante una verifica l'esecuzione in una finestra CMD separata è disabilitata.", "Modalità verifica", MessageBoxButton.OK, MessageBoxImage.Information); return; } if (!await CompileAsync()) return; if (string.IsNullOrWhiteSpace(_exePath) || !File.Exists(_exePath)) return; string outputFile = Path.Combine(Path.GetTempPath(), "cppstudent_output_" + Guid.NewGuid().ToString("N") + ".txt"); string psCommand = "$ErrorActionPreference='Continue'; & '" + _exePath.Replace("'", "''") + "' 2>&1 | Tee-Object -FilePath '" + outputFile.Replace("'", "''") + "'; $exitCode=$LASTEXITCODE; Write-Host ''; Write-Host ('Programma terminato. Codice uscita: ' + $exitCode); Write-Host 'Premi INVIO per chiudere questa console.'; Read-Host"; var psi = new ProcessStartInfo("powershell.exe", "-NoLogo -NoProfile -ExecutionPolicy Bypass -Command \"" + psCommand.Replace("\"", "\\\"") + "\"") { UseShellExecute = true, WorkingDirectory = Path.GetDirectoryName(_exePath) ?? Path.GetTempPath(), WindowStyle = ProcessWindowStyle.Normal }; StatusText.Text = "Programma in esecuzione..."; using Process? process = Process.Start(psi); if (process != null) await process.WaitForExitAsync(); _programOutput = File.Exists(outputFile) ? (await File.ReadAllTextAsync(outputFile)).Trim() : ""; if (_exerciseStates.TryGetValue(_activeKey, out ExerciseState? state)) { state.ProgramOutput = _programOutput; SaveExerciseStates(); } OutputBox.Text = string.IsNullOrWhiteSpace(_programOutput) ? "Programma terminato senza produrre output." : "OUTPUT PROGRAMMA:\n\n" + _programOutput; StatusText.Text = "Esecuzione terminata"; } '''
text=text[:run_start]+run_method+text[run_end:]
compile_start=text.find('private async Task CompileAsync()'); compile_end=text.find('private async void TestServer_Click',compile_start)
if compile_start<0 or compile_end<0: raise SystemExit('ERRORE: CompileAsync non trovato')
compile_method=r'''private async Task CompileAsync() { if (!_compilationAllowed) { OutputBox.Text = "Il docente ha temporaneamente inibito la compilazione sui client."; return false; } try { string gpp = BundledCompilerPath; if (!File.Exists(gpp)) { _compileOutput = "Installazione incompleta: il compilatore C++17 incorporato non è stato trovato.\n\nReinstalla CV+ Compilatore Alunno dalla Release ufficiale."; OutputBox.Text = _compileOutput; return false; } string dir = Path.Combine(Path.GetTempPath(), "CppStudentClient"); Directory.CreateDirectory(dir); string stem = "compito_" + Guid.NewGuid().ToString("N"); string cpp = Path.Combine(dir, stem + ".cpp"); _exePath = Path.Combine(dir, stem + ".exe"); File.WriteAllText(cpp, Editor.Text, new UTF8Encoding(false)); string arguments = $"-std=c++17 -Wall -Wextra -fdiagnostics-color=never -o \"{_exePath}\" \"{cpp}\""; var psi = new ProcessStartInfo(gpp, arguments) { UseShellExecute = false, RedirectStandardOutput = true, RedirectStandardError = true, CreateNoWindow = true, WorkingDirectory = dir }; ConfigureCompilerEnvironment(psi); using var process = Process.Start(psi) ?? throw new InvalidOperationException("Impossibile avviare il compilatore C++17 incorporato."); string stdout = await process.StandardOutput.ReadToEndAsync(); string stderr = await process.StandardError.ReadToEndAsync(); await process.WaitForExitAsync(); string diagnostics = string.Join(Environment.NewLine, new[] { stdout, stderr }.Where(value => !string.IsNullOrWhiteSpace(value))); if (process.ExitCode == 0 && File.Exists(_exePath)) { _compileOutput = string.IsNullOrWhiteSpace(diagnostics) ? "Compilazione C++17 riuscita senza avvisi." : "Compilazione C++17 riuscita.\n\n" + diagnostics.Trim(); } else { _compileOutput = $"Compilazione C++17 non riuscita (codice {process.ExitCode}).\n\n" + (string.IsNullOrWhiteSpace(diagnostics) ? "Il compilatore non ha restituito dettagli." : diagnostics.Trim()); } OutputBox.Text = _compileOutput; if (_exerciseStates.TryGetValue(_activeKey, out ExerciseState? state)) { state.CompileOutput = _compileOutput; SaveExerciseStates(); } return process.ExitCode == 0 && File.Exists(_exePath); } catch (Exception ex) { _compileOutput = "Errore durante la compilazione C++17:\n\n" + ex.Message; OutputBox.Text = _compileOutput; if (_exerciseStates.TryGetValue(_activeKey, out ExerciseState? state)) { state.CompileOutput = _compileOutput; SaveExerciseStates(); } return false; } } '''
text=text[:compile_start]+compile_method+text[compile_end:]
text=text.replace('} catch (Exception ex) { if (showErrors) MessageBox.Show(BuildNetworkError(ex), "Modalità sessione non disponibile", MessageBoxButton.OK, MessageBoxImage.Warning); } finally { _serverModeCheckRunning = false; }','} catch (Exception ex) { ApplySessionMode("esercitazione"); ApplyCompilationPermission(true); if (showErrors) MessageBox.Show(BuildNetworkError(ex), "Modalità sessione non disponibile", MessageBoxButton.OK, MessageBoxImage.Warning); } finally { _serverModeCheckRunning = false; }',1)
send_start=text.find('private async void Send_Click(object sender, RoutedEventArgs e)'); send_end=text.find('private bool ValidateSubmission',send_start)
if send_start<0 or send_end<0: raise SystemExit('ERRORE: Send_Click non trovato')
send_method=r'''private async void Send_Click(object sender, RoutedEventArgs e) { SaveCurrentExercise(); if (!ValidateSubmission(out int registerNumber, out _)) return; string type = GetTaskType(); string requested = Microsoft.VisualBasic.Interaction.InputBox("Quanti esercizi vuoi inviare al docente?\n\nSaranno inviati gli esercizi dal numero 1 al numero indicato.", "Numero esercizi da inviare", Math.Max(1, GetExerciseNumber()).ToString()); if (string.IsNullOrWhiteSpace(requested)) { StatusText.Text = "Invio annullato"; return; } if (!int.TryParse(requested.Trim(), out int exerciseCount) || exerciseCount <= 0 || exerciseCount > 100) { MessageBox.Show("Inserisci un numero di esercizi compreso tra 1 e 100.", "Numero non valido", MessageBoxButton.OK, MessageBoxImage.Warning); return; } string modeLabel = _verificationMode ? "VERIFICA" : "ESERCITAZIONE"; if (MessageBox.Show($"Confermi l'invio?\n\nModalità: {modeLabel}\nN° registro: {registerNumber}\nAlunno: {StudentNameBox.Text.Trim()}\nClasse: {ClassBox.Text.Trim()}\nTipologia: {type}\nEsercizi da inviare: da 1 a {exerciseCount}", "Conferma consegna multipla", MessageBoxButton.YesNo, MessageBoxImage.Question, MessageBoxResult.No) != MessageBoxResult.Yes) { StatusText.Text = "Invio annullato"; return; } try { SaveSettings(); string address = NormalizeServerAddress(ServerBox.Text) + "/submit"; int sent = 0; for (int exerciseNumber = 1; exerciseNumber <= exerciseCount; exerciseNumber++) { string key = BuildExerciseKey(type, exerciseNumber); if (!_exerciseStates.TryGetValue(key, out ExerciseState? state)) { state = new ExerciseState { Code = DefaultCode, Elapsed = TimeSpan.Zero }; _exerciseStates[key] = state; } var timings = _exerciseStates.ToDictionary(pair => pair.Key, pair => (long)pair.Value.Elapsed.TotalSeconds); var payload = new { studentId = registerNumber.ToString(), registerNumber, studentName = StudentNameBox.Text.Trim(), className = ClassBox.Text.Trim(), assignmentType = type, taskType = type, tipologia = type, type = type, exerciseId = exerciseNumber.ToString(), exerciseNumber, sessionCode = SessionBox.Text.Trim(), sessionMode = _verificationMode ? "verifica" : "esercitazione", exerciseTimeSeconds = (long)state.Elapsed.TotalSeconds, exerciseTimes = timings, code = state.Code ?? DefaultCode, compileOutput = state.CompileOutput ?? "", programOutput = state.ProgramOutput ?? "" }; using var content = new StringContent(JsonSerializer.Serialize(payload), Encoding.UTF8, "application/json"); StatusText.Text = $"Invio esercizio {exerciseNumber} di {exerciseCount}..."; using HttpResponseMessage response = await _http.PostAsync(address, content); string message = await response.Content.ReadAsStringAsync(); if (!response.IsSuccessStatusCode) throw new HttpRequestException($"Esercizio {exerciseNumber}: il server ha risposto {(int)response.StatusCode}: {message}"); sent++; } StatusText.Text = $"Consegnati {sent} esercizi alle {DateTime.Now:HH:mm:ss}"; MessageBox.Show($"Invio completato.\n\nEsercizi consegnati: {sent}", "Consegna completata", MessageBoxButton.OK, MessageBoxImage.Information); if (_verificationMode) { ClearLocalVerificationData(); _allowClose = true; Close(); } } catch (Exception ex) { StatusText.Text = "Invio fallito"; MessageBox.Show(BuildNetworkError(ex), "Impossibile inviare i compiti", MessageBoxButton.OK, MessageBoxImage.Warning); } } '''
text=text[:send_start]+send_method+text[send_end:]
cs.write_text(text,encoding='utf-8-sig')
print('PATCH CLIENT APPLICATA')
